//
//  SnapshotRenderer.swift
//  ggaebiz
//
//  Created by suyeon on 10/7/25.
//

import SwiftUI

struct SnapshotRenderer {
    @MainActor func renderCanvasView<Content: View>(baseImage: UIImage, size: CGSize, stickers: [Sticker], stickerView: @escaping () -> Content) async -> UIImage? {
        let content = ComposedCanvasView(baseImage: baseImage, size: size, stickers: stickers, stickerView: stickerView)

        return exeucute(content)
    }

    @MainActor func renderSummaryCard(cardImage: UIImage, hours: Int, minute: Int) async -> UIImage? {
        let cardImage = ZStack(alignment: .bottom) {
            Image(uiImage: cardImage)
                .resizable()
                .scaledToFit()

            HStack(spacing: 0) {
                timerText(value: hours, showColon: true)
                timerText(value: minute, showColon: false)
            }
            .padding(.bottom, 35)
        }

        return exeucute(cardImage)
    }

    private func timerText(
        value: Int,
        showColon: Bool = true
    ) -> some View {
        HStack(spacing: 0.0) {
            Text(String(format: "%02d", value))
                .zuumeFont(
                    weight: .bold700,
                    size: 80.0,
                    kerning: 4.0
                )
                .frame(width: 68.0)
                .foregroundStyle(.white)

            if showColon {
                Image(.imageColonTimerProgress)
                    .foregroundStyle(.white)
                    .padding(.horizontal, 16.0)
            }
        }
    }

    @MainActor func renderTimeStamps(_ views: [any View]) async -> [UIImage] {
        var images: [UIImage] = []

        for view in views {
            if let image = exeucute(AnyView(view)) {
                images.append(image)
            }
        }

        return images
    }

    @MainActor private func exeucute<Content: View>(_ content: Content) -> UIImage? {
        let renderer = ImageRenderer(content: content)
        renderer.scale = UIScreen.main.scale
        renderer.isOpaque = false

        if let img = renderer.uiImage {
            return img
        }
        return nil
    }
}

content.text:
네, `@MainActor`를 클래스 전체에 올리는 게 훨씬 낫습니다.

**현재 상황:** 모든 메서드(`renderCanvasView`, `renderSummaryCard`, `renderTimeStamps`, `exeucute`)가 이미 `@MainActor`입니다. `timerText`만 빠져 있는데, 이것도 SwiftUI View를 빌드하는 코드라 사실상 Main Actor 컨텍스트에서 호출됩니다.

**struct 레벨로 올리면 좋은 이유:**

1. **중복 제거** - 메서드마다 `@MainActor` 붙이는 게 불필요한 반복
2. **실수 방지** - 나중에 메서드 추가할 때 `@MainActor` 빼먹을 위험 없음
3. **의도 명확화** - "이 타입은 Main Actor에서만 쓰는 렌더러"라는 게 한눈에 보임
4. **`ImageRenderer`가 `@MainActor` 필수** - 이 struct의 존재 목적 자체가 Main Actor에 묶여 있음

```swift
@MainActor
struct SnapshotRenderer {
    func renderCanvasView<Content: View>(...) async -> UIImage? { ... }
    func renderSummaryCard(...) async -> UIImage? { ... }
    func renderTimeStamps(_ views: [any View]) async -> [UIImage] { ... }
    private func timerText(...) -> some View { ... }
    private func exeucute<Content: View>(_ content: Content) -> UIImage? { ... }
}
```

혹시 `nonisolated`로 빼야 할 메서드가 생기면 그때 개별적으로 `nonisolated`를 붙이면 됩니다. 바꿔드릴까요?

